module top_module(
    input CLK,
    input reset,
    output reg CLK_div
);reg [3:0] countdown;

    always @ (posedge CLK or posedge reset) begin
        if (reset) begin
            countdown <= 0;
            CLK_div <= 0;
        end
        else begin
            countdown <= countdown + 1;
            if (countdown == 4) begin
                countdown <= 0;
                CLK_div <= ~CLK_div;
            end
        end
    end

endmodule
